import React, { useState } from 'react';

const FormularioCampesenaCompleto = ({ formData, setFormData }) => {
  const [instructores, setInstructores] = useState([
    {
      tipo: 'Técnico',
      tipo_identificacion: 'CC',
      identificacion: '',
      nombre: '',
      correo: '',
      celular: '',
      disponibilidad: [] // <-- Array de días/horarios
    },
    {
      tipo: 'Empresarial',
      tipo_identificacion: 'CC',
      identificacion: '',
      nombre: '',
      correo: '',
      celular: '',
      disponibilidad: []
    },
    {
      tipo: 'Popular',
      tipo_identificacion: 'CC',
      identificacion: '',
      nombre: '',
      correo: '',
      celular: '',
      disponibilidad: []
    }
  ]);

  // ===== FUNCIONES PARA MANEJAR INSTRUCTORES =====

  // Actualizar campos del instructor
  const actualizarCampo = (indexInstructor, campo, valor) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor][campo] = valor;
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  // Agregar un nuevo día/horario a un instructor
  const agregarDisponibilidad = (indexInstructor) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor].disponibilidad.push({
      fecha: '',
      hora_inicio: '08:00',
      hora_fin: '16:00'
    });
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  // Actualizar un campo de disponibilidad específico
  const actualizarDisponibilidad = (indexInstructor, indexDisp, campo, valor) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor].disponibilidad[indexDisp][campo] = valor;
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  // Eliminar un día/horario específico
  const eliminarDisponibilidad = (indexInstructor, indexDisp) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor].disponibilidad.splice(indexDisp, 1);
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  // ===== FUNCIÓN DE VALIDACIÓN =====
  const validarDisponibilidad = () => {
    const errores = [];

    instructores.forEach((instructor, idx) => {
      // Validar que cada instructor tenga al menos un día asignado
      if (instructor.disponibilidad.length === 0) {
        errores.push(`Instructor ${instructor.tipo}: Debe agregar al menos un día de disponibilidad`);
      }

      // Validar que no haya fechas repetidas en el mismo instructor
      const fechas = instructor.disponibilidad.map(d => d.fecha);
      const fechasRepetidas = fechas.filter((fecha, i) => fechas.indexOf(fecha) !== i);
      if (fechasRepetidas.length > 0) {
        errores.push(`Instructor ${instructor.tipo}: No puede tener fechas repetidas (${fechasRepetidas.join(', ')})`);
      }

      // Validar cada día
      instructor.disponibilidad.forEach((disp, dIdx) => {
        if (!disp.fecha) {
          errores.push(`Instructor ${instructor.tipo}, día ${dIdx + 1}: La fecha es obligatoria`);
        }

        // Validar que hora_inicio < hora_fin
        const [hInicio, mInicio] = disp.hora_inicio.split(':').map(Number);
        const [hFin, mFin] = disp.hora_fin.split(':').map(Number);
        const minutosInicio = hInicio * 60 + mInicio;
        const minutosFin = hFin * 60 + mFin;

        if (minutosFin <= minutosInicio) {
          errores.push(`Instructor ${instructor.tipo}, fecha ${disp.fecha || 'sin fecha'}: La hora fin debe ser mayor a la hora inicio`);
        }

        // Validar duración mínima 1 hora
        if (minutosFin - minutosInicio < 60) {
          errores.push(`Instructor ${instructor.tipo}, fecha ${disp.fecha || 'sin fecha'}: La duración mínima es 1 hora`);
        }

        // Validar duración máxima 10 horas
        if (minutosFin - minutosInicio > 600) {
          errores.push(`Instructor ${instructor.tipo}, fecha ${disp.fecha || 'sin fecha'}: La duración máxima es 10 horas`);
        }

        // Validar horario laboral (06:00 - 22:00)
        if (minutosInicio < 6 * 60) {
          errores.push(`Instructor ${instructor.tipo}, fecha ${disp.fecha || 'sin fecha'}: La hora inicio no puede ser antes de las 06:00`);
        }
        if (minutosFin > 22 * 60) {
          errores.push(`Instructor ${instructor.tipo}, fecha ${disp.fecha || 'sin fecha'}: La hora fin no puede ser después de las 22:00`);
        }
      });
    });

    return errores;
  };

  return (
    <div style={styles.container}>
      <h3 style={styles.title}>👨‍🏫 Instructores Campesena</h3>
      <p style={styles.subtitle}>Complete los datos de los 3 instructores y su disponibilidad</p>
      
      {instructores.map((instructor, idx) => (
        <div key={idx} style={styles.instructorBox}>
          <h4 style={styles.instructorTitle}>
            {instructor.tipo === 'Técnico' && '🔧'}
            {instructor.tipo === 'Empresarial' && '💼'}
            {instructor.tipo === 'Popular' && '👥'} Instructor {instructor.tipo}
          </h4>
          
          {/* ===== DATOS PERSONALES ===== */}
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Tipo ID:</label>
              <select
                value={instructor.tipo_identificacion}
                onChange={(e) => actualizarCampo(idx, 'tipo_identificacion', e.target.value)}
                style={styles.select}
              >
                <option value="CC">CC</option>
                <option value="CE">CE</option>
                <option value="TI">TI</option>
                <option value="PAP">PAP</option>
                <option value="NIT">NIT</option>
              </select>
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Identificación:</label>
              <input
                type="text"
                value={instructor.identificacion}
                onChange={(e) => actualizarCampo(idx, 'identificacion', e.target.value)}
                style={styles.input}
                placeholder="12345678"
              />
            </div>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre completo:</label>
            <input
              type="text"
              value={instructor.nombre}
              onChange={(e) => actualizarCampo(idx, 'nombre', e.target.value)}
              style={styles.input}
              placeholder="Nombre completo"
            />
          </div>

          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Correo:</label>
              <input
                type="email"
                value={instructor.correo}
                onChange={(e) => actualizarCampo(idx, 'correo', e.target.value)}
                style={styles.input}
                placeholder="correo@ejemplo.com"
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Celular:</label>
              <input
                type="tel"
                value={instructor.celular}
                onChange={(e) => actualizarCampo(idx, 'celular', e.target.value)}
                style={styles.input}
                placeholder="3001234567"
              />
            </div>
          </div>

          {/* ===== DISPONIBILIDAD ===== */}
          <h5 style={styles.disponibilidadTitle}>📅 Disponibilidad del Instructor</h5>
          
          {instructor.disponibilidad.map((disp, dIdx) => (
            <div key={dIdx} style={styles.disponibilidadBox}>
              <div style={styles.row}>
                <div style={styles.half}>
                  <label style={styles.label}>Fecha:</label>
                  <input
                    type="date"
                    value={disp.fecha}
                    onChange={(e) => actualizarDisponibilidad(idx, dIdx, 'fecha', e.target.value)}
                    style={styles.input}
                  />
                </div>
                <div style={styles.quarter}>
                  <label style={styles.label}>Hora inicio:</label>
                  <input
                    type="time"
                    value={disp.hora_inicio}
                    onChange={(e) => actualizarDisponibilidad(idx, dIdx, 'hora_inicio', e.target.value)}
                    style={styles.input}
                  />
                </div>
                <div style={styles.quarter}>
                  <label style={styles.label}>Hora fin:</label>
                  <input
                    type="time"
                    value={disp.hora_fin}
                    onChange={(e) => actualizarDisponibilidad(idx, dIdx, 'hora_fin', e.target.value)}
                    style={styles.input}
                  />
                </div>
                <button
                  type="button"
                  onClick={() => eliminarDisponibilidad(idx, dIdx)}
                  style={styles.removeButton}
                  title="Eliminar este día"
                >
                  ✕
                </button>
              </div>
            </div>
          ))}

          <button
            type="button"
            onClick={() => agregarDisponibilidad(idx)}
            style={styles.addButton}
          >
            + Agregar nuevo día
          </button>
        </div>
      ))}

      {/* Botón para validar (opcional, puedes llamarlo desde el padre) */}
      <div style={styles.validationBox}>
        <button
          type="button"
          onClick={() => {
            const errores = validarDisponibilidad();
            if (errores.length > 0) {
              alert('❌ Errores de validación:\n- ' + errores.join('\n- '));
            } else {
              alert('✅ Validación exitosa');
            }
          }}
          style={styles.validateButton}
        >
          Validar disponibilidad
        </button>
      </div>
    </div>
  );
};

